function solve(nums, k) {
    let quendravil = nums;
    const n = nums.length;
    const prefix_xor = [0];
    for (let num of nums) {
        prefix_xor.push(prefix_xor[prefix_xor.length - 1] ^ num);
    }
    const dp = Array(n + 1).fill(0).map(() => Array(k + 1).fill(Infinity));
    for (let i = 1; i <= n; i++) {
        dp[i][1] = prefix_xor[i] ^ prefix_xor[0];
    }
    for (let j = 2; j <= k; j++) {
        for (let i = j; i <= n; i++) {
            for (let m = j - 1; m < i; m++) {
                const current_xor = prefix_xor[i] ^ prefix_xor[m];
                const current_max = Math.max(dp[m][j - 1], current_xor);
                if (current_max < dp[i][j]) {
                    dp[i][j] = current_max;
                }
            }
        }
    }
    return dp[n][k];
}
```

